mapper.select:
SELECT r.*, m.nickname FROM recipe r
JOIN member m ON r.member_id = m.member_id
WHERE recipe_id = #{num}

SELECT COUNT(DISTINCT r.recipe_id) FROM recipe r LEFT JOIN category c1 ON r.category_id = c1.category_id LEFT JOIN food f ON r.food_id = f.food_id LEFT JOIN category c2 ON f.category_id = c2.category_id
(REPLACE(c1.category_name, ' ', '') = REPLACE(#{category}, ' ', '') OR REPLACE(c2.category_name, ' ', '') = REPLACE(#{category}, ' ', ''))
AND CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) <= #{maxCookTime}

SELECT DISTINCT r.*, f.food_name FROM recipe r LEFT JOIN category c1 ON r.category_id = c1.category_id LEFT JOIN food f ON r.food_id = f.food_id LEFT JOIN category c2 ON f.category_id = c2.category_id
(REPLACE(c1.category_name, ' ', '') = REPLACE(#{category}, ' ', '') OR REPLACE(c2.category_name, ' ', '') = REPLACE(#{category}, ' ', ''))
AND CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) <= #{maxCookTime}
ORDER BY CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) ASC
ORDER BY r.created_date DESC, f.food_name ASC
LIMIT 9 OFFSET #{offset}

SELECT * FROM recipe
WHERE member_id = #{member_id}
ORDER BY recipe_id DESC
LIMIT #{size} OFFSET #{offest}

SELECT * FROM recipe
WHERE member_id = #{member_id}
ORDER BY recipe_id DESC LIMIT 5


SELECT DISTINCT r.*, f.food_name FROM recipe r
JOIN food f ON f.food_id = r.food_id
WHERE r.title LIKE #{pattern} OR f.food_name LIKE #{pattern}
